/*
 * Static config.h for the cross-platform encfs_decrypt drop-in.
 *
 * In the full encfs build this file is generated by CMake from config.h.cmake
 * and records host feature probes (xattr, lchmod, dirent d_type, ...). The
 * decrypt-only library compiled here uses none of those features (they live in
 * the FUSE / DirNode code, which is not part of this subtree), so a fixed
 * minimal config is sufficient and keeps the package self-contained -- no
 * generation step required.
 */
#ifndef ENCFS_DECRYPT_STATIC_CONFIG_H
#define ENCFS_DECRYPT_STATIC_CONFIG_H

#ifndef VERSION
#define VERSION "1.9.5"
#endif

/* National Language Support is disabled in this build; intl/gettext.h then
 * defines gettext(x) as a no-op passthrough. */
#ifndef ENABLE_NLS
#define ENABLE_NLS 0
#endif

#endif /* ENCFS_DECRYPT_STATIC_CONFIG_H */
